void test_case(void)
{
    /* Initialize per CSV procedure */
#ifdef GPIO0
    GIC_EnableIRQ(87);
#endif
#ifdef GPIO1
    GIC_EnableIRQ(88);
#endif

    /* Enable system-level GPIO interrupts */
    write_reg(MIZAR_LSS_SYSREG_INTR_EN1, LSS_SYSREG_INTR_EN1_GPIO0_INTR | LSS_SYSREG_INTR_EN1_GPIO1_INTR);

    /* Drive pattern to external register to generate edges */
    write_reg(0xA0243FFC, 0xFFFFFFFF);

    for (int i = 0; i < 32; ++i) {
        unsigned int wr_val = (1u << i);
        /* Program per-pin: (1u<<20)|(1u<<18)|(1u<<16) at MIZAR_GPIO_GP0_GPIO_8 + (i*4) */
        write_reg(MIZAR_GPIO_GP0_GPIO_8 + (i * 4), (1u<<20) | (1u<<18) | (1u<<16));

        /* Clear RAW_STCLR and enable group EN1 bit for pin i */
        write_reg(MIZAR_GPIO_GPIO_INTR_RAW_STCLR1, wr_val);
        write_reg(MIZAR_GPIO_GP0_INTR1_INTR_EN1, wr_val);

        /* Generate negedge by toggling 0xA0243FFC: set high then clear single bit */
        int_pend = 1;
        write_reg(0xA0243FFC, 0xFFFFFFFF);
        wait_on(10);
        write_reg(0xA0243FFC, ~wr_val);

        /* Poll with timeout */
        int timeout = 1000000;
        while (int_pend && --timeout) { /* spin */ }
        if (timeout == 0) {
            printf("ERROR: timeout waiting for interrupt on pin %d\n", i);
            test_err++;
        }

        /* In ISR, status check and clear are handled; here, nothing else */
    }

    finish(test_err ? 1 : 0);
}
